import React from "react";
import { BulletContainer, Container } from "./styles";
import ColorBullet from "./ColorBullet";
import useSettings from "../../storage/useSettings";
import { Box } from "@mui/material";
import { Gender } from "../../types/types";
import { removeDuplicates } from "../../utils/utils";

type ColorBulletsProps = {
	gender: Gender;
	selectedColorId: number | undefined;
	onSelectColor: (colorId: number) => void;
};

const ColorBullets = ({
	gender,
	selectedColorId,
	onSelectColor,
}: ColorBulletsProps) => {
	const { stocks } = useSettings();
	return (
		<Container>
			{removeDuplicates(stocks, "colorId")
				.filter((s) => s.gender === gender)
				.map((stock) => (
					<BulletContainer
						key={stock.colorId}
						selected={stock.colorId === selectedColorId}
						onClick={() => onSelectColor(stock.colorId)}
					>
						<ColorBullet
							key={stock.colorId}
							color={{
								id: stock.colorId,
								name: stock.colorName,
								hex: stock.colorHex
							}} />
					</BulletContainer>
				))}
		</Container>
	);
};

export default ColorBullets;
