import React from "react";
import useSettings from "../../storage/useSettings";
import { Box, Button, Typography } from "@mui/material";
import { Gender } from "../../types/types";

type SelectSizeProps = {
    selectedColorId: number;
    gender: Gender;
    selectedSizeId: number | undefined;
    onSelectSize: (sizeId: number) => void;
}

const SelectSize = ({ selectedColorId, gender, selectedSizeId, onSelectSize }: SelectSizeProps) => {
    const { stocks } = useSettings();
    return (
        <Box gap={2} mt={4} display='flex' flexWrap='wrap'>
            {stocks.filter((s) => s.colorId === selectedColorId && s.gender === gender)
                .map((stock) => (
                    <Box display='flex' flexDirection='column'>
                        <Button
                            disabled={stock.quantity === 0}
                            key={stock.sizeId}
                            onClick={() => onSelectSize(stock.sizeId)}
                            variant={stock.sizeId === selectedSizeId ? "contained" : "outlined"}
                        >
                            {stock.sizeName}
                        </Button>
                        {stock.quantity === 0 &&
                            <Typography variant="caption" paddingLeft='2px'>
                                Esgotado
                            </Typography>
                        }
                    </Box>
                ))}
        </Box>
    )
}

export default SelectSize;
